import * as React from 'react'
import styled, { css } from 'styled-components'

type FontSize = 'heading1' | 'heading2' | 'heading3' | 'heading4'

const HeadingBase = styled.h1<{ $level: number }>(
  ({
    $level,
    theme: {
      color,
      typography: { fontSize },
    },
  }) => css`
    margin: 0;
    color: ${color.primaryText};
    font-family: 'Montserrat';
    letter-spacing: ${$level === 1 || $level === 2 ? '-2px' : 'unset'};
    font-size: ${fontSize[`heading${$level}` as FontSize]};
  `
)

type DefaultProps = {
  level?: 1 | 2 | 3 | 4 | 5
  className?: string
}

type HeadingProps = DefaultProps & Omit<React.ComponentProps<'h1'>, keyof DefaultProps>

export const Heading: React.FC<React.PropsWithChildren<HeadingProps>> = ({
  level = 1,
  children,
  className,
}) => {
  const heading = `h${level}` as React.ElementType
  return (
    <HeadingBase as={heading} $level={level} className={className}>
      {children}
    </HeadingBase>
  )
}

import * as React from 'react'
import styled, { css } from 'styled-components'

type FontSize = 'body' | 'bodyS' | 'bodyXS' | 'bodyXXS'
type FontWeight = 'regular' | 'medium' | 'bold' | 'black'

type StyledBodyProps = {
  $size: string
  $fontWeight: string
}

const BodyBase = styled.p<StyledBodyProps>(
  ({ $size, $fontWeight, color: textColor, theme: { typography, color } }) => css`
    display: block;
    font-family: 'Hind';
    color: ${textColor || color.primaryText};
    font-weight: ${typography.fontWeight[$fontWeight as FontWeight]};
    font-size: ${typography.fontSize[`body${$size}` as FontSize]};
  `
)

type AsElement = 'span' | 'p' | 'label' | 'figcaption'

type ElementProps<T extends AsElement> = T extends 'label'
  ? React.LabelHTMLAttributes<HTMLLabelElement>
  : T extends 'span'
    ? React.HTMLAttributes<HTMLSpanElement>
    : T extends 'p'
      ? React.HTMLAttributes<HTMLParagraphElement>
      : React.HTMLAttributes<HTMLElement>

type DefaultProps = {
  className?: string
  size?: 'S' | 'XS' | 'XXS'
  fontWeight?: 'regular' | 'medium' | 'bold' | 'black'
  type?: AsElement
  color?: string
  children: React.ReactNode | string
}

type BodyProps = DefaultProps & ElementProps<AsElement>

export const Body: React.FC<React.PropsWithChildren<BodyProps>> = ({
  size = '',
  fontWeight = 'regular',
  type = 'p',
  color,
  children,
  className,
  ...props
}) => (
  <BodyBase
    as={type}
    $size={size}
    $fontWeight={fontWeight}
    color={color}
    className={className}
    {...props}
  >
    {children}
  </BodyBase>
)

