 1→import { useState } from 'react'
 2→import styled, { css } from 'styled-components'
 3→
 4→import { ContactDetails } from './ContactDetails'
 5→import { DeliveryDetails } from './DeliveryDetails'
 6→import { StepIndicator } from './StepIndicator'
 7→import { type ContactDetailsFormData, type DeliveryDetailsFormData } from './validation'
 8→
 9→type Step = {
10→  id: 'Contact details' | 'Delivery details'
11→}
12→
13→const steps: Step[] = [{ id: 'Contact details' }, { id: 'Delivery details' }]
14→
15→const defaultData: ContactDetailsFormData & DeliveryDetailsFormData = {
16→  firstName: '',
17→  lastName: '',
18→  address: '',
19→  city: '',
20→  postcode: '',
21→  email: '',
22→  phone: '',
23→}
24→
25→const FormContainer = styled.div(
26→  ({ theme: { color, borderRadius } }) => css`
27→    width: 100%;
28→    min-height: 480px;
29→    margin-right: 1.5rem;
30→    background: ${color.formBackground};
31→    padding: 1.5rem;
32→    border-radius: ${borderRadius.s};
33→  `
34→)
35→
36→export const MultiStepForm = () => {
37→  const [currentStep, setCurrentStep] = useState(0)
38→  const [formData, setFormData] = useState(defaultData)
39→
40→  const handleNext = () => {
41→    if (currentStep < steps.length - 1) {
42→      setCurrentStep(currentStep + 1)
43→    }
44→  }
45→
46→  const handlePrevious = () => {
47→    if (currentStep > 0) {
48→      setCurrentStep(currentStep - 1)
49→    }
50→  }
51→
52→  const handleFormData = (data: Partial<typeof defaultData>) => {
53→    setFormData((prev) => ({ ...prev, ...data }))
54→  }
55→
56→  const currentStepData = steps[currentStep]
57→
58→  const renderCurrentStep = () => {
59→    switch (currentStepData.id) {
60→      case 'Contact details': {
61→        return (
62→          <ContactDetails formData={formData} setFormData={handleFormData} onNext={handleNext} />
63→        )
64→      }
65→      case 'Delivery details': {
66→        return (
67→          <DeliveryDetails
68→            formData={formData}
69→            setFormData={handleFormData}
70→            onPrevious={handlePrevious}
71→          />
72→        )
73→      }
74→      default: {
75→        return null
76→      }
77→    }
78→  }
79→
80→  return (
81→    <FormContainer>
82→      <StepIndicator
83→        title={currentStepData.id}
84→        currentStep={currentStep + 1}
85→        amountOfSteps={steps.length}
86→      />
87→      {renderCurrentStep()}
88→    </FormContainer>
89→  )
90→}
