    rating: 4.2,
    categories: ['burgers', 'comfort food'],
    menu: { food, dessert, drinks },
  },
  {
    id: '2',
    name: 'Kara Fin',
    specialty: 'Sarma (wine leafs with rice)',
    photoUrl:
