    categories: ['burgers', 'pizza'],
    menu: { food, dessert, drinks },
  },
  {
    id: '3',
    name: 'De Oliewinkel',
    specialty: 'Olive oil',
    photoUrl: 'https://duyt4h9nfnj50.cloudfront.net/search_home/FastFood.jpg',
    categories: ['comfort food'],
    isClosed: true,
    menu: { food, dessert, drinks },
  },
